 flex-direction: column;
 gap: 16px;
}

.metro-details__section {
 background: #ffffff;
 border-radius: 8px;
 padding: 20px;
 box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.metro-details__section h3 {
 margin: 0 0 12px;
 font-size: 16px;
 color: #1a237e;
 border-bottom: 1px solid #eeeeee;
 padding-bottom: 8px;
}

.metro-details__dl {
 display: grid;
 grid-template-columns: 140px 1fr;
 gap: 8px 12px;
 margin: 0;
 font-size: 14px;
}

.metro-details__dl dt {
 color: #666666;
 font-weight: 600;
}

.metro-details__dl dd {
 color: #333333;
 margin: 0;
}

.metro-details__qr {
 font-family: monospace;
 background: #f5f5f5;
 padding: 4px 8px;
 border-radius: 4px;
 font-size: 12px;
 word-break: break-all;
}

.metro-details__no-qr {
 color: #666666;
 font-style: italic;
 font-size: 14px;
 margin: 0;
}
