","import React from "react";

interface KPIData {
 totalBookings: number;
 totalPayments: number;
 totalRevenue: number;
 activePassCount: number;
 pendingVerifications: number;
 openComplaints: number;
 qrTickets: number;
}

const KPI_COLORS = ["#1a237e", "#4caf50", "#ff9800", "#2196f3", "#9c27b0", "#f44336", "#00bcd4"];

export default function AdminKPIs({ data }: { data: KPIData }) {
 const items = [
 { label: "Total Bookings", val: data.totalBookings },
 { label: "Total Payments", val: data.totalPayments },
 { label: "Total Revenue", val: `₹${data.totalRevenue}` },
 { label: "Active Passes", val: data.activePassCount },
 { label: "Pending Verifications", val: data.pendingVerifications },
 { label: "Open Complaints", val: data.openComplaints },
 { label: "QR Tickets", val: data.qrTickets }
 ];

 return (
 <div className="metro-admin__kpis">
 {items.map((item, i) => (
 <div
 key={item.label}
 className="metro-admin__kpi-card"
 style={{ borderLeftColor: KPI_COLORS[i] }}
 >
 <span className="metro-admin__kpi-value">{item.val}</span>
 <span className="metro-admin__kpi-label">{item.label}</span>
 </div>
 ))}
 </div>
 );
}
