","import React from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./AdminComplaints.css";

interface AdminComplaintsProps {
 complaints: any[];
 onRefresh: () => void;
}

export default function AdminComplaints({ complaints, onRefresh }: AdminComplaintsProps) {
 async function handleStatusChange(sysId: string, newStatus: string) {
 try {
 await MetroService.update("x_1877508_metro_0_metro_complaint", sysId, {
 status: newStatus
 });
 onRefresh();
 } catch (e) {
 console.error("Failed to update complaint status", e);
 }
 }

 if (complaints.length === 0) return <p>No complaints found.</p>;

 return (
 <div className="metro-admin__section">
 <h2 className="metro-admin__section-title">Complaints</h2>
 <div className="metro-admin__cards">
 {complaints.map((c) => (
 <div key={c.sys_id.value} className="metro-admin__card">
 <div className="metro-admin__row"><span>Complaint #</span><span>{display(c.complaint_number) || display(c.number)}</span></div>
 <div className="metro-admin__row"><span>Passenger</span><span>{display(c.passenger)}</span></div>
 <div className="metro-admin__row"><span>Booking</span><span>{display(c.booking)}</span></div>
 <div className="metro-admin__row"><span>Issue Type</span><span>{display(c.issue_type)}</span></div>
 <div className="metro-admin__row"><span>Description</span><span>{display(c.description)}</span></div>
 <div className="metro-admin__row"><span>Assigned To</span><span>{display(c.assigned_to)}</span></div>
 <div className="metro-complaints__status-row">
 <span>Status</span>
 <select
 className="metro-complaints__select"
 value={value(c.status)}
 onChange={(e) => handleStatusChange(c.sys_id.value, e.target.value)}
 >
 <option value="new">New</option>
 <option value="in_progress">In Progress</option>
 <option value="resolved">Resolved</option>
 </select>
 </div>
 </div>
 ))}
 </div>
 </div>
 );
}
","import React, { useState, useEffect, useCallback } from "react";
import { MetroService } from "../services/MetroService";
import { value } from "../utils/fields";
import AdminKPIs from "./AdminKPIs";
import AdminBookings from "./AdminBookings";
import AdminPayments from "./AdminPayments";
import AdminComplaints from "./AdminComplaints";
import "./AdminDashboard.css";

interface AdminDashboardProps {
 navigateToView: (view: string, id?: string) => void;
}

export default function AdminDashboard({ navigateToView }: AdminDashboardProps) {
 const [bookings, setBookings] = useState<any[]>([]);
 const [payments, setPayments] = useState<any[]>([]);
 const [complaints, setComplaints] = useState<any[]>([]);
 const [passes, setPasses] = useState<any[]>([]);
 const [verifications, setVerifications] = useState<any[]>([]);
 const [qrTickets, setQrTickets] = useState<any[]>([]);
 const [loading, setLoading] = useState(true);

 const fetchData = useCallback(async () => {
 try {
 const [bk, py, cp, ps, vr, qr] = await Promise.all([
 MetroService.list("x_1877508_metro_0_metro_booking", "ORDERBYDESCsys_created_on", 20),
 MetroService.list("x_1877508_metro_0_metro_payment", "ORDERBYDESCsys_created_on", 20),
 MetroService.list("x_1877508_metro_0_metro_complaint", "ORDERBYDESCsys_created_on", 20),
 MetroService.list("x_1877508_metro_0_metro_student_pass", "pass_status=active"),
 MetroService.list("x_1877508_metro_0_metro_student_profile", "verification_status=pending"),
 MetroService.list("x_1877508_metro_0_metro_qr_ticket")
 ]);
 setBookings(bk); setPayments(py); setComplaints(cp);
 setPasses(ps); setVerifications(vr); setQrTickets(qr);
 } catch (e) {
 console.error("Admin dashboard fetch failed", e);
 } finally {
 setLoading(false);
 }
 }, []);

 useEffect(() => { fetchData(); }, [fetchData]);

 if (loading) return <div className="metro-admin"><p>Loading dashboard...</p></div>;

 const totalRevenue = payments.reduce((sum, p) => sum + (parseFloat(value(p.amount)) || 0), 0);
 const openComplaints = complaints.filter(
 (c) => value(c.status) === "new" || value(c.status) === "in_progress"
 ).length;

 const kpiData = {
 totalBookings: bookings.length,
 totalPayments: payments.length,
 totalRevenue,
 activePassCount: passes.length,
 pendingVerifications: verifications.length,
 openComplaints,
 qrTickets: qrTickets.length
 };

 return (
 <div className="metro-admin">
 <h1 className="metro-admin__title">Admin Dashboard</h1>
 <AdminKPIs data={kpiData} />
 <AdminBookings bookings={bookings} />
 <AdminPayments payments={payments} />
 <AdminComplaints complaints={complaints} onRefresh={fetchData} />
 </div>
 );
}
","import React, { useState, useEffect, useCallback } from "react";
import Navigation from "./components/Navigation";
import HomePage from "./components/HomePage";
import BookTicket from "./components/BookTicket";
import StudentPass from "./components/StudentPass";
import Complaint from "./components/Complaint";
import MyTickets from "./components/MyTickets";
import TicketDetails from "./components/TicketDetails";
import PaymentHistory from "./components/PaymentHistory";
import PassDetails from "./components/PassDetails";
import AdminDashboard from "./components/AdminDashboard";
import "./app.css";

type ViewName =
 | "home"
 | "book-ticket"
 | "student-pass"
 | "complaint"
 | "my-tickets"
 | "ticket-details"
 | "payment-history"
 | "pass-details"
 | "admin-dashboard";

interface ViewState {
 view: ViewName;
 recordId: string | null;
}

function getViewFromUrl(): ViewState {
 const params = new URLSearchParams(window.location.search);
 return {
 view: (params.get("view") as ViewName) || "home",
 recordId: params.get("id") || null
 };
}

export default function App() {
 const [currentView, setCurrentView] = useState<ViewState>(getViewFromUrl);

 useEffect(() => {
 const onPopState = () => setCurrentView(getViewFromUrl());
 window.addEventListener("popstate", onPopState);
 return () => window.removeEventListener("popstate", onPopState);
 }, []);

 const navigateToView = useCallback(
 (viewName: string, recordId?: string | null) => {
 const params = new URLSearchParams({ view: viewName });
 if (recordId) params.set("id", recordId);
 const relativePath = `${window.location.pathname}?${params}`;
 const title = `Metro - ${viewName.charAt(0).toUpperCase() + viewName.slice(1)}`;

 if (window.self !== window.top) {
 (window as any).CustomEvent.fireTop(
 "magellanNavigator.permalink.set",
 { relativePath, title }
 );
 }
 window.history.pushState({ viewName, recordId }, "", relativePath);
 document.title = title;
 setCurrentView({ view: viewName as ViewName, recordId: recordId || null });
 },
 []
 );

 const { view, recordId } = currentView;

 const renderView = () => {
 switch (view) {
 case "book-ticket":
 return <BookTicket navigateToView={navigateToView} />;
 case "student-pass":
 return <StudentPass navigateToView={navigateToView} />;
 case "complaint":
 return <Complaint navigateToView={navigateToView} />;
 case "my-tickets":
 return <MyTickets navigateToView={navigateToView} />;
 case "ticket-details":
 return <TicketDetails recordId={recordId} navigateToView={navigateToView} />;
 case "payment-history":
 return <PaymentHistory navigateToView={navigateToView} />;
 case "pass-details":
 return <PassDetails navigateToView={navigateToView} />;
 case "admin-dashboard":
 return <AdminDashboard navigateToView={navigateToView} />;
 default:
 return <HomePage navigateToView={navigateToView} />;
 }
 };

 return (
 <div className="metro-app">
 <Navigation currentView={view} navigateToView={navigateToView} />
 <main className="metro-app__content">{renderView()}</main>
 </div>
 );
}
